definition.script:
pipeline {
    agent any
    stages {
        stage('Configure Genomic Frontend Settings') {
            steps {
                script {
                    def envFile = '/usr/local/docker-config/httpd/httpd.env'
                    def genomicVars = [
                        "VITE_ENABLE_GENE_QUERY=${env.ENABLE_GENE_QUERY}",
                        "VITE_ENABLE_SNP_QUERY=${env.ENABLE_SNP_QUERY}",
                        "VITE_VARIANT_EXPLORER=${env.VARIANT_EXPLORER}",
                        "VITE_VARIANT_EXPLORER_TYPE=${env.VARIANT_EXPLORER_TYPE}",
                        "VITE_EXPLORER_MAX_COUNT=${env.EXPLORER_MAX_COUNT}",
                        "VITE_VARIANT_EXPLORER_EXCLUDE_COLUMNS=${env.VARIANT_EXPLORER_EXCLUDE_COLUMNS}"
                    ]

                    for (entry in genomicVars) {
                        def key = entry.split('=')[0]
                        sh "sed -i '/^${key}=/d' ${envFile}"
                        sh "echo '${entry}' >> ${envFile}"
                    }
                }
            }
        }

        stage('Configure HPDS Genomic Data') {
            steps {
                script {
                    if (env.Include_Genomic_Data == "true") {
                        sh "sed -i 's/^SPRING_PROFILES_ACTIVE=.*/SPRING_PROFILES_ACTIVE=bch-dev/' /usr/local/docker-config/hpds/hpds.env"
                    } else {
                        sh "sed -i 's/^SPRING_PROFILES_ACTIVE=.*/SPRING_PROFILES_ACTIVE=/' /usr/local/docker-config/hpds/hpds.env"
                    }
                }
            }
        }
    }
}
